theme.custom_css_code:
.psuk-diagram-wrap {
  width: 100%;
  padding: 20px;
  border-radius: 20px;
  background: rgba(255,255,255,0.03);
  border: 1px solid rgba(255,255,255,0.1);
  font-family: Arial, sans-serif;
  box-sizing: border-box;
}

.psuk-diagram-row {
  display: grid;
  grid-template-columns: 180px 1fr 42px;
  gap: 14px;
  align-items: center;
  margin-bottom: 14px;
}

.psuk-diagram-row:last-child {
  margin-bottom: 0;
}

.psuk-diagram-label {
  color: #ededed;
  font-size: 14px;
  line-height: 1.35;
}

.psuk-diagram-track {
  width: 100%;
  height: 14px;
  border-radius: 999px;
  background: rgba(255,255,255,0.08);
  overflow: hidden;
  position: relative;
  box-shadow: inset 0 0 0 1px rgba(255,255,255,0.05);
}

.psuk-diagram-fill {
  display: block;
  height: 100%;
  min-width: 10px;
  border-radius: 999px;
  background: linear-gradient(90deg, #ffffff 0%, #e7e7e7 38%, #cfcfcf 70%, #adadad 100%);
  box-shadow: 0 0 12px rgba(255,255,255,0.2);
  position: relative;
}

.psuk-diagram-fill::after {
  content: "";
  position: absolute;
  left: 2px;
  right: 2px;
  top: 2px;
  bottom: 2px;
  border-radius: 999px;
  background: linear-gradient(180deg, rgba(255,255,255,0.34), rgba(255,255,255,0.08));
}

.psuk-diagram-value {
  color: #d0d0d0;
  font-size: 13px;
  text-align: right;
  font-weight: 700;
}

@media (max-width: 680px) {
  .psuk-diagram-row {
    grid-template-columns: 1fr;
    gap: 8px;
  }

  .psuk-diagram-value {
    text-align: left;
  }

  .psuk-diagram-track {
    height: 12px;
  }
}

.psuk-games-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 16px;
  width: 100%;
  background: transparent;
  font-family: Arial, sans-serif;
}

.psuk-game-card {
  position: relative;
  padding: 18px;
  border-radius: 20px;
  background: linear-gradient(180deg, rgba(255,255,255,0.06), rgba(255,255,255,0.025));
  border: 1px solid rgba(255,255,255,0.1);
  color: #f5f5f5;
  min-height: 150px;
  overflow: hidden;
}

.psuk-game-card::after {
  content: "";
  position: absolute;
  right: -18px;
  top: -18px;
  width: 72px;
  height: 72px;
  border-radius: 50%;
  background: rgba(255,255,255,0.04);
}

.psuk-game-icon {
  display: flex;
  gap: 5px;
  margin-bottom: 14px;
  height: 20px;
  align-items: flex-end;
}

.psuk-game-icon span {
  display: block;
  width: 8px;
  background: #ffffff;
  border-radius: 8px 8px 2px 2px;
  opacity: 0.95;
}

.psuk-game-icon span:nth-child(1) { height: 10px; }
.psuk-game-icon span:nth-child(2) { height: 16px; }
.psuk-game-icon span:nth-child(3) { height: 20px; }

.psuk-live-icon span,
.psuk-table-icon span,
.psuk-roulette-icon span,
.psuk-jackpot-icon span,
.psuk-mobile-icon span {
  width: 10px;
}

.psuk-game-name {
  font-size: 18px;
  font-weight: 700;
  margin-bottom: 6px;
}

.psuk-game-meta {
  font-size: 13px;
  line-height: 1.45;
  color: #c8c8c8;
  margin-bottom: 16px;
}

.psuk-game-bar {
  width: 100%;
  height: 10px;
  border-radius: 999px;
  background: rgba(255,255,255,0.08);
  overflow: hidden;
  position: relative;
  box-shadow: inset 0 0 0 1px rgba(255,255,255,0.05);
}

.psuk-game-fill {
  display: block;
  height: 100%;
  min-width: 8px;
  border-radius: 999px;
  background: linear-gradient(90deg, #ffffff 0%, #e7e7e7 40%, #bdbdbd 100%);
  box-shadow: 0 0 10px rgba(255,255,255,0.2);
}

@media (max-width: 900px) {
  .psuk-games-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 560px) {
  .psuk-games-grid {
    grid-template-columns: 1fr;
  }

  .psuk-game-card {
    min-height: auto;
  }
}

.psuk-brand-table-wrap {
  width: 100%;
  background: transparent;
  font-family: Arial, sans-serif;
}

.psuk-brand-table-scroll {
  width: 100%;
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
  border: 1px solid rgba(255,255,255,0.12);
  border-radius: 18px;
  background: rgba(255,255,255,0.03);
}

.psuk-brand-table {
  width: 100%;
  min-width: 640px;
  border-collapse: collapse;
  color: #f4f4f4;
}

.psuk-brand-table td {
  padding: 14px 16px;
  border-bottom: 1px solid rgba(255,255,255,0.08);
  vertical-align: top;
  font-size: 14px;
  line-height: 1.5;
}

.psuk-brand-table tr:last-child td {
  border-bottom: none;
}

.psuk-brand-table td:first-child {
  width: 34%;
  color: #bdbdbd;
  font-weight: 600;
  background: rgba(255,255,255,0.02);
}

@media (max-width: 640px) {
  .psuk-brand-table td {
    padding: 12px 14px;
    font-size: 13px;
  }
}
